#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define pii pair<int,int>
#define fr first
#define se second
#define pb push_back
using namespace std;
const int N = 605;
int Q,B,Min[N];set<int> st;
int min(int x,int y){return (x<y?x:y);}
int max(int x,int y){return (x>y?x:y);}
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
int main(){
    Q=read(),B=sqrt(Q);
    for(int i=1;i<=B;i++)Min[i]=i-1;
    while(Q--){
        char opt;cin>>opt;
        if(opt=='A'){
            int x=read();st.insert(x);
            for(int i=1;i<=B;i++)Min[i]=min(Min[i],x%i);
        }else{
            int x=read(),Ans=x-1;
            if(x<=B){cout<<Min[x]<<"\n";continue;}
            for(int i=0;i<=3000000/x;i++){
                auto p=st.lower_bound(i*x);
                if(p!=st.end())Ans=min(Ans,(*p)-i*x);
            }
            cout<<Ans<<"\n";
        }
    }
    return 0;
}
